            "anvi-gen-variability-network -i variability-profile-txt \\\n  -o variability_profile.gexf \\\n  --include-competing-NTs noise-robust",
            "anvi-gen-variability-network -i variability-profile-txt \\\n  -o variability_profile.gexf \\\n  --include-competing-NTs noise-robust \\\n  --edge-variable departure_from_consensus"
