            "anvi-get-short-reads-from-bam BAM_FILE_1.bam BAM_FILE_2.bam \\\n  -c contigs-db \\\n  -p profile-db \\\n  -C collection \\\n  -b bin \\\n  --output-file OUTPUT.fa",
