          "id": "concatenated-gene-alignment-fasta",
          "kind": "data",
          "title": "concatenated-gene-alignment-fasta",
          "artifactType": "FASTA",
          "description": "This file contains the alignment information for multiple genes across different organisms . Basically, a single gene alignment compares a single gene’s sequence across multiple organisms. For example, you could align some specific rRNA sequence across all of the organisms in your sample. This alignment highlights both mutations and insertions and deletions (indicated with dashes).",
          "version": "main",
          "requires": [],
          "provides": [],
