          "kind": "data",
          "title": "hmm-list",
          "artifactType": "TXT",
          "description": "The hmm-list file is a TAB-delimited file with at least three columns: Here is an example of an hmm-list using the HMM Ribosomal_L16 and Ribosomal_S2 from the internal anvi’o collection Bacteria_71:",
          "version": "main",
          "requires": [],
          "provides": [],
          "parameters": [],
          "examples": [],
          "docsUrl": "https://anvio.org/help/main/artifacts/hmm-list/",
