          "id": "augustus-gene-calls",
          "kind": "data",
          "title": "augustus-gene-calls",
          "artifactType": "TXT",
          "description": "A gene call file from AUGUSTUS . AUGUSTUS is a tool to predict genes from a variety of Eurkaryotic genomes. This includes predicting the 5’ UTR and 3’ UTR, as well as introns. You can search a sequence in the Augustus web interface . After a search, you can export the results as a .gff text file.",
          "version": "main",
          "requires": [],
          "provides": [],
